// Serializes documents as part of the JSON response payload with no escaping.
TEST(RestJsonServerResponseTest, DocumentOutput) {
  class Handler final : public RecordingHandler {
   public:
    smithy::Outcome<DocumentTypeOutput> DocumentType(const DocumentTypeInput& input) override {
      (void)input;
      return [] {
  DocumentTypeOutput v{};
  v.stringValue = "string";
  v.documentValue = [] {
  smithy::DocumentMap map;
  map.emplace("foo", smithy::Document(std::string("bar")));
  return smithy::Document(std::move(map));
}();
  return v;
}();
    }
  };
  RestJsonServer server(std::make_shared<Handler>());
  const smithy::http::HttpResponse response = server.Handler()(MinimalRequestForDocumentType());
  EXPECT_EQ(response.status, 200);
  EXPECT_EQ(response.headers.Get("Content-Type").value_or("<missing>"), "application/json");
  EXPECT_TRUE(smithy::testing::JsonBodyEquals("{\n    \"stringValue\": \"string\",\n    \"documentValue\": {\n        \"foo\": \"bar\"\n    }\n}", response.body));
}

