// Tests how timestamp response headers are serialized
TEST(RestJsonServerResponseTest, RestJsonTimestampFormatHeaders) {
  class Handler final : public RecordingHandler {
   public:
    smithy::Outcome<TimestampFormatHeadersOutput> TimestampFormatHeaders(const TimestampFormatHeadersInput& input) override {
      (void)input;
      return [] {
  TimestampFormatHeadersOutput v{};
  v.memberEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.memberDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.defaultFormat = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetEpochSeconds = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetHttpDate = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  v.targetDateTime = smithy::Timestamp::FromEpochMilliseconds(1576540098000LL);
  return v;
}();
    }
  };
  RestJsonServer server(std::make_shared<Handler>());
  const smithy::http::HttpResponse response = server.Handler()(MinimalRequestForTimestampFormatHeaders());
  EXPECT_EQ(response.status, 200);
  EXPECT_EQ(response.headers.Get("X-defaultFormat").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
  EXPECT_EQ(response.headers.Get("X-memberDateTime").value_or("<missing>"), "2019-12-16T23:48:18Z");
  EXPECT_EQ(response.headers.Get("X-memberEpochSeconds").value_or("<missing>"), "1576540098");
  EXPECT_EQ(response.headers.Get("X-memberHttpDate").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
  EXPECT_EQ(response.headers.Get("X-targetDateTime").value_or("<missing>"), "2019-12-16T23:48:18Z");
  EXPECT_EQ(response.headers.Get("X-targetEpochSeconds").value_or("<missing>"), "1576540098");
  EXPECT_EQ(response.headers.Get("X-targetHttpDate").value_or("<missing>"), "Mon, 16 Dec 2019 23:48:18 GMT");
}

