// Serializes a complex error with no message member
TEST(RestJsonServerErrorTest, RestJsonComplexErrorWithNoMessage) {
  class Handler final : public RecordingHandler {
   public:
    smithy::Outcome<GreetingWithErrorsOutput> GreetingWithErrors(const GreetingWithErrorsInput& input) override {
      (void)input;
      smithy::Error error = smithy::Error::Modeled("ComplexError", "");
      error.set_detail([] {
  ComplexError v{};
  v.Header = "Header";
  v.TopLevel = "Top level";
  v.Nested = [] {
  ComplexNestedErrorData v{};
  v.Foo = "bar";
  return v;
}();
  return v;
}());
      return error;
    }
  };
  RestJsonServer server(std::make_shared<Handler>());
  const smithy::http::HttpResponse response = server.Handler()(MinimalRequestForGreetingWithErrors());
  EXPECT_EQ(response.status, 403);
  EXPECT_EQ(response.headers.Get("Content-Type").value_or("<missing>"), "application/json");
  EXPECT_EQ(response.headers.Get("X-Amzn-Errortype").value_or("<missing>"), "ComplexError");
  EXPECT_EQ(response.headers.Get("X-Header").value_or("<missing>"), "Header");
  EXPECT_TRUE(smithy::testing::JsonBodyEquals("{\n    \"TopLevel\": \"Top level\",\n    \"Nested\": {\n        \"Fooooo\": \"bar\"\n    }\n}", response.body));
}

